mapper.select:
WITH checkpoint_with_interval AS ( SELECT checkpoint_raw_id, instance_id, collected_at, checkpoint_type, checkpoints_timed, checkpoints_req, checkpoint_write_time, checkpoint_sync_time, buffers_checkpoint, buffers_backend, avg_buffers_per_sec, wal_bytes, wal_files_added, wal_files_removed, checkpoint_distance, created_at, -- 계산 필드 checkpoint_write_time + checkpoint_sync_time AS total_time, CASE WHEN (checkpoints_req + checkpoints_timed) > 0 THEN (checkpoints_req::NUMERIC / (checkpoints_req + checkpoints_timed) * 100) ELSE 0 END AS request_ratio, -- 이전 checkpoint와의 시간 간격 (분) EXTRACT(EPOCH FROM (collected_at - LAG(collected_at) OVER (ORDER BY collected_at))) / 60.0 AS interval_minutes FROM checkpoint_raw WHERE instance_id = #{instanceId} AND collected_at BETWEEN #{startTime} AND #{endTime}
AND checkpoint_type IN
#{type}
) SELECT checkpoint_raw_id, instance_id, collected_at, checkpoint_type, checkpoints_timed, checkpoints_req, checkpoint_write_time, checkpoint_sync_time, total_time, buffers_checkpoint, buffers_backend, avg_buffers_per_sec, wal_bytes, wal_files_added, wal_files_removed, checkpoint_distance, request_ratio, interval_minutes, created_at FROM checkpoint_with_interval ORDER BY collected_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM checkpoint_raw
WHERE instance_id = #{instanceId}
  AND collected_at BETWEEN #{startTime} AND #{endTime}

      AND checkpoint_type IN

          #{type}
